<template>
  <nav class="nav">
    <a href="#!" class="logo"><img src="@/assets/img/logo.svg" alt="logo" /> <span>vue weather</span></a>

    <div class="nav__search">
      <img @click="switchTheme" src="@/assets/img/dots.svg" alt="dots" />

      <input type="text" placeholder="Введите название города" v-model="city" @keydown.enter="getWeather(city), (city = '')" />
    </div>
  </nav>
</template>

<script>
import { mapActions } from "vuex";

export default {
  data() {
    return {
      city: "",
    };
  },

  methods: {
    ...mapActions(["getWeather"]),

    switchTheme() {
      let value = document.body.style.getPropertyValue("--bg");

      if (value == "white") {
        document.body.style.setProperty("--bg", "#2d2a2a");
        document.body.style.setProperty("--text", "#4793FF");
      } else {
        document.body.style.setProperty("--bg", "white");
        document.body.style.setProperty("--text", "black");
      }
    },
  },

  created() {
    document.body.style.setProperty("--bg", "white");
  },
};
</script>
