<template>
  <div class="main__week_day">
    <h3 class="main__week_day-title">{{ getWeekDay }}</h3>
    <p class="main__week_day-text">{{ getDay }} {{ getMounth }}</p>
    <img :src="getImg" alt="" />
    <p class="main__week_day-title">+ {{ Math.round(day.temp.max) }}°</p>
    <p class="main__week_day-text">Ощущается: +{{ Math.round(day.feels_like.day) }}°</p>
    <p class="main__week_day-text">{{ description }}</p>
  </div>
</template>

<script>
import unix from "@/unix";
import weatherName from "@/icons";

export default {
  props: {
    day: {
      typeof: Object,
    },
  },

  computed: {
    description() {
      return this.day.weather[0].description;
    },

    getImg() {
      return weatherName[this.description] || weatherName["ясно"];
    },
    getDay() {
      return unix(this.day.dt, "day");
    },
    getWeekDay() {
      if (this.getDay == new Date().getDate()) {
        return "Сегодня";
      } else if (this.getDay == new Date().getDate() + 1) {
        return "Завтра";
      } else {
        return unix(this.day.dt, "weekDay");
      }
    },
    getMounth() {
      return unix(this.day.dt, "mounth");
    },
  },
  mounted() {},
};
</script>
