import { createStore } from "vuex";
import axios from "axios";

export default createStore({
  state: {
    weather: null,
    apiKey: "c2a39ccefcbffaa3ebc62e38041c6f20",
  },

  getters: {},

  mutations: {
    getWeather(state, payload) {
      state.weather = payload;
    },
  },

  actions: {
    async getWeather(context, city) {
      try {
        let response = await axios.get(`https://api.openweathermap.org/geo/1.0/direct?q=${city}&appid=${context.state.apiKey}`);

        let { lat, lon, local_names } = response.data[0];

        if (local_names.ru.toLowerCase() == city.toLowerCase()) {
          let response2 = await axios.get(`https://api.openweathermap.org/data/2.8/onecall?lat=${lat}&lon=${lon}&exclude=minutely,hourly,alerts&appid=${context.state.apiKey}&units=metric&lang=ru`);

          const weatherInfo = { ...response2.data, name: city, local_names };

          context.commit("getWeather", weatherInfo);
          // console.log(local_names.ru);
        }
      } catch (error) {
        console.error(error);
      }

      // q={city name}&appid={API key} Должно остаться в запросе
    },
  },
});
